### 2. Add Optional Runtime Warning
\`\`\`rust
impl Logger {
    fn log(&self, level: Level, msg: &str, keyvals: &[(&str, &str)]) {
        let mut inner = self.inner.write().unwrap_or_else(|e| e.into_inner());

        // Warn once about performance overhead
        if inner.report_caller && !inner.warned_caller_overhead {
            inner.warned_caller_overhead = true;
            if !inner.suppress_caller_warning {
                let _ = io::stderr().write_all(
                    b"[charmed_log] PERF WARNING: caller reporting enabled - expect 100x slowdown\\n"
                );
            }
        }
        // ... rest of logging
    }

    /// Suppress the runtime performance warning for caller reporting.
    pub fn suppress_caller_warning(mut self) -> Self {
        let mut inner = self.inner.write().unwrap_or_else(|e| e.into_inner());
        inner.suppress_caller_warning = true;
        drop(inner);
        self
    }
}
\`\`\`

### 3. Add Benchmarks
\`\`\`rust
use criterion::{criterion_group, criterion_main, Criterion, BenchmarkId};

fn bench_log_without_caller(c: &mut Criterion) {
    let logger = Logger::new();

    c.bench_function("log_no_caller", |b| {
        b.iter(|| {
            logger.info("benchmark message", &[("key", "value")]);
        });
    });
}

fn bench_log_with_caller(c: &mut Criterion) {
    let mut opts = Options::default();
    opts.report_caller = true;
    let logger = Logger::with_options(opts);

    c.bench_function("log_with_caller", |b| {
        b.iter(|| {
            logger.info("benchmark message", &[("key", "value")]);
        });
    });
}

fn bench_comparison(c: &mut Criterion) {
    let mut group = c.benchmark_group("caller_overhead");

    for caller_enabled in [false, true] {
        let mut opts = Options::default();
        opts.report_caller = caller_enabled;
        let logger = Logger::with_options(opts);

        group.bench_with_input(
            BenchmarkId::new("log", if caller_enabled { "with_caller" } else { "no_caller" }),
            &logger,
            |b, logger| {
                b.iter(|| {
                    logger.info("test", &[]);
                });
            },
        );
    }
    group.finish();
}

criterion_group!(benches, bench_log_without_caller, bench_log_with_caller, bench_comparison);
criterion_main!(benches);
