    // Capture output
    let output = Arc::new(Mutex::new(Vec::new()));
    let output_clone = output.clone();

    // Spawn thread that changes formatter
    let logger_clone = logger.clone();
    let changer = std::thread::spawn(move || {
        for _ in 0..1000 {
            logger_clone.set_formatter(Formatter::Text);
            logger_clone.set_formatter(Formatter::Json);
        }
    });

    // Spawn thread that logs
    let logger_clone = logger.clone();
    let log_out = output.clone();
    let log_thread = std::thread::spawn(move || {
        for i in 0..1000 {
            logger_clone.info(&format!("msg{}", i), &[]);
        }
    });

    changer.join().unwrap();
    log_thread.join().unwrap();

    // Each log entry should be valid JSON or valid Text, not mixed
    let output = output.lock().unwrap();
    for line in output.lines() {
        // Should parse as one format or the other, never malformed
        assert!(is_valid_json(line) || is_valid_text(line));
    }
}
```

